import{_ as d,r as a,o as u,c as p,a as e,b as o,t as s,d as t,w,e as i}from"./app-d223f2a5.js";const f={},m={id:"frontmatter-title-관련",tabindex:"-1"},y=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),g={class:"table-of-contents"},_=i('<hr><h2 id="project-25-part-two" tabindex="-1"><a class="header-anchor" href="#project-25-part-two" aria-hidden="true">#</a> Project 25, part two</h2><p>There are a number of well-known quotes from Steve Jobs, but if I had to pick one – my all-time favorite – it would be this: “it is in Apple’s DNA that technology alone is not enough – it’s technology married with liberal arts, married with the humanities, that yields us the results that make our heart sing.”</p><p>Multipeer connectivity is another one of those frameworks that should set off sparks in your brain: “how can I use this make something great?” Honestly, I can’t answer that question for you. As Saint Steve said, technology alone is not enough – you won’t build something truly great just by shipping a thin layer over Apple’s APIs.</p><p>It’s easy to think to yourself, “what can I make that’s different from everything else?” What you <em>ought</em> to be thinking is “what unique perspective does my background and experience give me that lets me build a fresh take on an existing idea?” In 2015 (seven years after the App Store launched) Microsoft spent north of $100 million acquiring Wonderlist, which was – shock! – a to do list app.</p><p>What I’m saying is that your idea doesn’t need to be special, and really your code doesn’t need to be that special either. Because what matters – the part that makes our heart sing – is where you blend all that with what makes you <em>you</em>. If you’ve used 10 to do apps and none quite scratch the itch you have, it’s time for you to make your own. And with over a billion people out there using iOS, you’ll find that there are hundreds of thousands of people that have exactly that same itch, and would happily hand over a buck or two for your solution.</p><p>Whether your app idea ends up building on multipeer networking, iBeacons, Core Image, or more – it doesn’t matter. What matters is that you’re giving yourself the skills you need to build the app of your dreams, and you should be darned proud of yourself.</p><p><strong>Today you should work through the wrap up chapter for project 25, complete its review, then work through all three of its challenges.</strong></p>',8),k={class:"hint-container details"},b=e("summary",null,"Wrap up",-1),v={href:"https://www.hackingwithswift.com/read/25/5/wrap-up",target:"_blank",rel:"noopener noreferrer"},x=e("p",null,"Multipeer connectivity is something that used to be awfully hard, but in iOS it's less than 150 lines of code to produce this entire app – and over half of that is code for the collection view and the image picker!",-1),I=e("p",null,"The advantage it has compared to traditional data sharing over Wi-Fi is that multipeer can use an existing Wi-Fi network, or can silently create a new Wi-Fi network or even a Bluetooth network depending on what's available. All this is an implementation detail that Apple solves on your behalf – we don’t have to care how it works.",-1),S=e("h4",{id:"review-what-you-learned",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#review-what-you-learned","aria-hidden":"true"},"#"),o(" Review what you learned")],-1),j=e("p",null,"Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.",-1),A={href:"https://www.hackingwithswift.com/review/hws/project-25-selfie-share",target:"_blank",rel:"noopener noreferrer"},T=i('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try your new knowledge to make sure you fully understand what’s going on:</p><ol><li>Show an alert when a user has disconnected from our multipeer network. Something like “Paul’s iPhone has disconnected” is enough.</li><li>Try sending text messages across the network. You can create a <code>Data</code> from a string using <code>Data(yourString.utf8)</code>, and convert a <code>Data</code> back to a string by using <code>String(decoding: yourData, as: UTF8.self)</code>.</li><li>Add a button that shows an alert controller listing the names of all devices currently connected to the session – use the <code>connectedPeers</code> property of your session to find that information.</li></ol>',3),W={class:"hint-container info"},q=e("p",{class:"hint-container-title"},"Wrap up - Additional",-1),D={href:"https://www.hackingwithswift.com/review/hws/project-25-selfie-share",target:"_blank",rel:"noopener noreferrer"},P=e("p",null,"Don’t forget to share your progress with others – holding yourself accountable is particularly important as we approach the final straight of this challenge!",-1),B=e("hr",null,null,-1);function C(r,L){const h=a("router-link"),n=a("ExternalLinkIcon"),l=a("YouTube"),c=a("TagLinks");return u(),p("div",null,[e("h1",m,[y,o(" "+s(r.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,s(r.$frontmatter.description),1)]),e("nav",g,[e("ul",null,[e("li",null,[t(h,{to:"#project-25-part-two"},{default:w(()=>[o("Project 25, part two")]),_:1})])])]),_,e("details",k,[b,e("p",null,[e("a",v,[o("📎link"),t(n)])]),t(l,{id:"H82q9rmL9mk"}),x,I,S,j,e("p",null,[e("a",A,[o("Click here to review what you learned in project 25."),t(n)])]),T]),e("div",W,[q,e("p",null,[e("a",D,[o("Review for Project 25: Selfie Share"),t(n)])])]),P,B,t(c)])}const F=d(f,[["render",C],["__file","84.html.vue"]]);export{F as default};
